source_sections.text:
{
  "day": "1",
  "heading": "Reach Gangotri from Dehradun",
  "sub_heading": "Drive distance: 242 km | Drive Duration: 8 hours",
  "details": "Transport will be arranged from ,Asli Pappu Da Dhaba, Dehradun at 5.00 am. The transport cost is ₹1550 (additional 5% GST) per trekker (one-way) (₹3100 for both onward and return journeys). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "2",
  "heading": "Trek from Gangotri (10,050 ft) to Chirbasa (11,630 ft)",
  "sub_heading": "Trek Distance: 10 km | Trek Duration: 6 hours",
  "details": "Moderate. Initial 300 m steep ascent followed by a very gradual ascent all the way."
}

{
  "day": "3",
  "heading": "Chirbasa (11,630 ft) to Bhojbasa (12,415 ft)",
  "sub_heading": "Trek Distance: 5 km | Trek Duration: 3 hours",
  "details": "Moderate. Initial 100 m ascent to get back on the trail. Very gradual ascent all the way to Bhojbasa"
}

{
  "day": "4",
  "heading": "Bhojbasa (12,415 ft) to Tapovan (14,203 ft)",
  "sub_heading": "Trek Distance: 6 km | Trek Duration: 9 hours",
  "details": "Difficult. Gradual ascent for 2.5 hours. 2 hours glacier walk followed by 1 hour of moderate ascent. Final 1.5 hours is a steep ascent."
}

{
  "day": "5",
  "heading": "Tapovan (14,203 ft) to Bhojbasa (12,415 ft)",
  "sub_heading": "Trek Distance: 6 km | Trek Duration: 5 hours",
  "details": "Moderate Difficult. Level trail to Chirbasa."
}

{
  "day": "6",
  "heading": "Bhojbasa (12,415 ft) to Gangotri (10,050 ft)",
  "sub_heading": "Trek Distance: 14 km | Trek Duration: 8 hours",
  "details": "Tricky descent over bouldery section"
}

{
  "day": "7",
  "heading": "Drive from Gangotri to Dehradun",
  "sub_heading": "Drive distance: 242 km | Drive Duration: 8 hours",
  "details": "The transport cost is ₹1550 (additional 5% GST) per trekker (one-way) (₹3100 for both onward and return journeys). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek.\nPlease note: The distance between campsites may vary by 100 meters depending on the weather conditions and the route you take. The altitude may also vary by 100 feet for similar reasons.\nDrop Location and Time: Asli Pappu Da Dhaba, Dehradun at 8.00 pm"
}

{
  "day": "8",
  "heading": "Buffer Day",
  "sub_heading": "If the buffer day is used,  you have to pay us Rs. 2,500 per day (INR) +5% GST. The money will be collected by the Trek Leader only if we use the buffer day.",
  "details": "This depends completely on the weather conditions on the trek and the call will be taken by the trek leader."
}
